import { lazy } from "react";
import { createBrowserRouter } from "react-router-dom";
import { RootLayout } from "@/components/layout/root-layout";

const DashboardPage = lazy(() => import("@/pages/dashboard/page"));
const AgentsPage = lazy(() => import("@/pages/agents/page"));
const AgentDetailPage = lazy(() => import("@/pages/agents/[id]/page"));
const TasksPage = lazy(() => import("@/pages/tasks/page"));
const TaskDetailPage = lazy(() => import("@/pages/tasks/[id]/page"));
const EpicsPage = lazy(() => import("@/pages/epics/page"));
const EpicDetailPage = lazy(() => import("@/pages/epics/[id]/page"));
const ChatPage = lazy(() => import("@/pages/chat/page"));
const ServicesPage = lazy(() => import("@/pages/services/page"));
const SchedulesPage = lazy(() => import("@/pages/schedules/page"));
const ScheduleDetailPage = lazy(() => import("@/pages/schedules/[id]/page"));
const UsagePage = lazy(() => import("@/pages/usage/page"));
const ConfigPage = lazy(() => import("@/pages/config/page"));
const ReposPage = lazy(() => import("@/pages/repos/page"));
const WorkflowsPage = lazy(() => import("@/pages/workflows/page"));
const WorkflowDetailPage = lazy(() => import("@/pages/workflows/[id]/page"));
const WorkflowRunDetailPage = lazy(() => import("@/pages/workflow-runs/[id]/page"));
const DebugPage = lazy(() => import("@/pages/debug/page"));
const NotFoundPage = lazy(() => import("@/pages/not-found/page"));

export const router = createBrowserRouter([
  {
    path: "/",
    element: <RootLayout />,
    children: [
      { index: true, element: <DashboardPage /> },
      { path: "agents", element: <AgentsPage /> },
      { path: "agents/:id", element: <AgentDetailPage /> },
      { path: "tasks", element: <TasksPage /> },
      { path: "tasks/:id", element: <TaskDetailPage /> },
      { path: "epics", element: <EpicsPage /> },
      { path: "epics/:id", element: <EpicDetailPage /> },
      { path: "chat", element: <ChatPage /> },
      { path: "chat/:channelId", element: <ChatPage /> },
      { path: "services", element: <ServicesPage /> },
      { path: "schedules", element: <SchedulesPage /> },
      { path: "schedules/:id", element: <ScheduleDetailPage /> },
      { path: "workflows", element: <WorkflowsPage /> },
      { path: "workflows/:id", element: <WorkflowDetailPage /> },
      { path: "workflow-runs/:id", element: <WorkflowRunDetailPage /> },
      { path: "usage", element: <UsagePage /> },
      { path: "config", element: <ConfigPage /> },
      { path: "repos", element: <ReposPage /> },
      { path: "debug", element: <DebugPage /> },
      { path: "*", element: <NotFoundPage /> },
    ],
  },
]);

import {
  BarChart3,
  Bug,
  Clock,
  GitBranch,
  LayoutDashboard,
  ListTodo,
  MessageSquare,
  Milestone,
  Server,
  Settings,
  Users,
  Workflow,
} from "lucide-react";
import { NavLink, useLocation } from "react-router-dom";
import {
  Sidebar,
  SidebarContent,
  SidebarFooter,
  SidebarGroup,
  SidebarGroupContent,
  SidebarGroupLabel,
  SidebarHeader,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
  SidebarRail,
  SidebarTrigger,
} from "@/components/ui/sidebar";
import { SwarmSwitcher } from "./swarm-switcher";

const navGroups = [
  {
    label: "Core",
    items: [
      { title: "Dashboard", path: "/", icon: LayoutDashboard },
      { title: "Agents", path: "/agents", icon: Users },
      { title: "Tasks", path: "/tasks", icon: ListTodo },
      { title: "Epics", path: "/epics", icon: Milestone },
    ],
  },
  {
    label: "Communication",
    items: [{ title: "Chat", path: "/chat", icon: MessageSquare }],
  },
  {
    label: "Operations",
    items: [
      { title: "Services", path: "/services", icon: Server },
      { title: "Schedules", path: "/schedules", icon: Clock },
      { title: "Workflows", path: "/workflows", icon: Workflow },
      { title: "Usage", path: "/usage", icon: BarChart3 },
    ],
  },
  {
    label: "System",
    items: [
      { title: "Config", path: "/config", icon: Settings },
      { title: "Repos", path: "/repos", icon: GitBranch },
      { title: "Debug", path: "/debug", icon: Bug },
    ],
  },
];

export function AppSidebar() {
  const location = useLocation();

  return (
    <Sidebar collapsible="icon">
      <SidebarHeader className="border-b border-sidebar-border">
        <NavLink
          to="/"
          className="flex h-10 items-center gap-2 group-data-[collapsible=icon]:justify-center"
        >
          <img
            src="/logo.png"
            alt="Agent Swarm"
            className="h-8 w-8 min-h-[32px] min-w-[32px] shrink-0 rounded"
          />
          <span className="text-lg font-semibold tracking-tight text-sidebar-foreground group-data-[collapsible=icon]:hidden">
            Agent Swarm
          </span>
        </NavLink>
        <div className="group-data-[collapsible=icon]:hidden">
          <SwarmSwitcher />
        </div>
      </SidebarHeader>

      <SidebarContent>
        {navGroups.map((group) => (
          <SidebarGroup key={group.label}>
            <SidebarGroupLabel>{group.label}</SidebarGroupLabel>
            <SidebarGroupContent>
              <SidebarMenu>
                {group.items.map((item) => {
                  const isActive =
                    item.path === "/"
                      ? location.pathname === "/"
                      : location.pathname.startsWith(item.path);
                  return (
                    <SidebarMenuItem key={item.path}>
                      <SidebarMenuButton asChild isActive={isActive}>
                        <NavLink to={item.path} end={item.path === "/"}>
                          <item.icon className="size-4" />
                          <span>{item.title}</span>
                        </NavLink>
                      </SidebarMenuButton>
                    </SidebarMenuItem>
                  );
                })}
              </SidebarMenu>
            </SidebarGroupContent>
          </SidebarGroup>
        ))}
      </SidebarContent>

      <SidebarFooter className="border-t border-sidebar-border">
        <SidebarMenu>
          <SidebarMenuItem>
            <SidebarTrigger className="w-full justify-start" />
          </SidebarMenuItem>
        </SidebarMenu>
      </SidebarFooter>

      <SidebarRail />
    </Sidebar>
  );
}

