 35→class ApiClient {
 36→  private getHeaders(): HeadersInit {
 37→    const config = getConfig();
 38→    const headers: HeadersInit = {
 39→      "Content-Type": "application/json",
 40→    };
 41→    if (config.apiKey) {
 42→      headers.Authorization = `Bearer ${config.apiKey}`;
 43→    }
 44→    return headers;
 45→  }
 46→
 47→  private getBaseUrl(): string {
 48→    const config = getConfig();
 49→    if (import.meta.env.DEV && config.apiUrl === "http://localhost:3013") {
 50→      return "";
 51→    }
 52→    return config.apiUrl;
 53→  }
 54→
 55→  async fetchAgents(includeTasks = true): Promise<AgentsResponse> {
 56→    const url = `${this.getBaseUrl()}/api/agents${includeTasks ? "?include=tasks" : ""}`;
 57→    const res = await fetch(url, { headers: this.getHeaders() });
 58→    if (!res.ok) throw new Error(`Failed to fetch agents: ${res.status}`);
 59→    return res.json();
 60→  }
 61→
 62→  async fetchAgent(id: string, includeTasks = true): Promise<AgentWithTasks> {
 63→    const url = `${this.getBaseUrl()}/api/agents/${id}${includeTasks ? "?include=tasks" : ""}`;
 64→    const res = await fetch(url, { headers: this.getHeaders() });
 65→    if (!res.ok) throw new Error(`Failed to fetch agent: ${res.status}`);
 66→    return res.json();
 67→  }
 68→
 69→  async updateAgentName(id: string, name: string): Promise<AgentWithTasks> {
 70→    const url = `${this.getBaseUrl()}/api/agents/${id}/name`;
 71→    const res = await fetch(url, {
 72→      method: "PUT",
 73→      headers: this.getHeaders(),
 74→      body: JSON.stringify({ name }),
 75→    });
 76→    if (!res.ok) {
 77→      const error = await res.json().catch(() => ({ error: "Failed to update name" }));
 78→      throw new Error(error.error || `Failed to update name: ${res.status}`);
 79→    }
 80→    return res.json();
 81→  }
 82→
 83→  async updateAgentProfile(
 84→    id: string,
 85→    profile: {
 86→      role?: string;
 87→      description?: string;
 88→      capabilities?: string[];
 89→      claudeMd?: string;
