102→    if (!res.ok) {
103→      const error = await res.json().catch(() => ({ error: "Failed to update profile" }));
104→      throw new Error(error.error || `Failed to update profile: ${res.status}`);
105→    }
106→    return res.json();
107→  }
108→
109→  async fetchTasks(filters?: {
110→    status?: string;
111→    agentId?: string;
112→    epicId?: string;
113→    scheduleId?: string;
114→    search?: string;
115→    includeHeartbeat?: boolean;
116→    limit?: number;
117→    offset?: number;
118→  }): Promise<TasksResponse> {
119→    const params = new URLSearchParams();
120→    if (filters?.status) params.set("status", filters.status);
121→    if (filters?.agentId) params.set("agentId", filters.agentId);
122→    if (filters?.epicId) params.set("epicId", filters.epicId);
123→    if (filters?.scheduleId) params.set("scheduleId", filters.scheduleId);
124→    if (filters?.search) params.set("search", filters.search);
125→    if (filters?.includeHeartbeat) params.set("includeHeartbeat", "true");
126→    if (filters?.limit != null) params.set("limit", String(filters.limit));
127→    if (filters?.offset != null) params.set("offset", String(filters.offset));
128→    const queryString = params.toString();
129→    const url = `${this.getBaseUrl()}/api/tasks${queryString ? `?${queryString}` : ""}`;
130→    const res = await fetch(url, { headers: this.getHeaders() });
131→    if (!res.ok) throw new Error(`Failed to fetch tasks: ${res.status}`);
132→    return res.json();
133→  }
