148→  method: "get",
149→  path: "/api/prompt-templates",
150→  pattern: ["api", "prompt-templates"],
151→  summary: "List prompt templates with optional filters",
152→  tags: ["PromptTemplates"],
153→  query: z.object({
154→    eventType: z.string().optional(),
155→    scope: z.string().optional(),
156→    scopeId: z.string().optional(),
