160→    200: { description: "List of prompt templates" },
161→  },
162→  auth: { apiKey: true },
163→});
164→
165→const upsertRoute = route({
166→  method: "put",
167→  path: "/api/prompt-templates",
168→  pattern: ["api", "prompt-templates"],
169→  summary: "Create or update a prompt template override",
170→  tags: ["PromptTemplates"],
171→  body: z.object({
172→    eventType: z.string().min(1),
173→    scope: z.enum(["global", "agent", "repo"]).optional(),
174→    scopeId: z.string().optional(),
175→    state: z.enum(["enabled", "default_prompt_fallback", "skip_event"]).optional(),
176→    body: z.string(),
177→    changedBy: z.string().optional(),
178→    changeReason: z.string().optional(),
179→  }),
180→  responses: {
181→    200: { description: "Upserted template" },
182→    400: { description: "Validation error" },
183→  },
184→  auth: { apiKey: true },
185→});
186→
187→// ─── Handler ─────────────────────────────────────────────────────────────────
188→
189→export async function handlePromptTemplates(
190→  req: IncomingMessage,
191→  res: ServerResponse,
192→  pathSegments: string[],
193→  queryParams: URLSearchParams,
194→): Promise<boolean> {
195→  // 3-segment literal: /api/prompt-templates/resolved
196→  if (resolvedRoute.match(req.method, pathSegments)) {
197→    const parsed = await resolvedRoute.parse(req, res, pathSegments, queryParams);
198→    if (!parsed) return true;
199→
200→    const { eventType, agentId, repoId } = parsed.query;
201→    if (!eventType) {
202→      jsonError(res, "eventType query parameter is required", 400);
203→      return true;
204→    }
205→
206→    const result = resolveTemplate(eventType, {}, { agentId, repoId });
207→    const dbResult = resolvePromptTemplate(eventType, agentId, repoId);
208→    const definition = getTemplateDefinition(eventType);
209→
210→    json(res, {
211→      resolution: result,
212→      dbResult,
213→      definition: definition
214→        ? {
215→            eventType: definition.eventType,
216→            header: definition.header,
217→            defaultBody: definition.defaultBody,
218→            variables: definition.variables,
219→            category: definition.category,
220→          }
221→        : null,
222→    });
223→    return true;
224→  }
225→
226→  // 3-segment literal: /api/prompt-templates/events
227→  if (eventsRoute.match(req.method, pathSegments)) {
228→    const parsed = await eventsRoute.parse(req, res, pathSegments, queryParams);
229→    if (!parsed) return true;
230→
231→    const definitions = getAllTemplateDefinitions();
232→    json(res, {
233→      events: definitions.map((d) => ({
234→        eventType: d.eventType,
235→        header: d.header,
236→        defaultBody: d.defaultBody,
237→        variables: d.variables,
238→        category: d.category,
239→      })),
240→    });
241→    return true;
242→  }
243→
244→  // 3-segment literal: /api/prompt-templates/preview
245→  if (previewRoute.match(req.method, pathSegments)) {
246→    const parsed = await previewRoute.parse(req, res, pathSegments, queryParams);
247→    if (!parsed) return true;
248→
249→    const { eventType, body: customBody, variables } = parsed.body;
250→    const definition = getTemplateDefinition(eventType);
251→    const templateBody = customBody ?? definition?.defaultBody ?? "";
252→    const header = definition?.header ?? "";
253→    const composed = header ? `${header}\n\n${templateBody}` : templateBody;
254→    const { result: rendered, unresolved } = interpolate(composed, variables ?? {});
255→
256→    json(res, { rendered, unresolved });
257→    return true;
258→  }
259→
260→  // 3-segment literal: /api/prompt-templates/render
261→  if (renderRoute.match(req.method, pathSegments)) {
262→    const parsed = await renderRoute.parse(req, res, pathSegments, queryParams);
263→    if (!parsed) return true;
264→
265→    const { eventType, variables, agentId, repoId } = parsed.body;
266→    const result = resolveTemplate(eventType, variables ?? {}, { agentId, repoId });
267→    json(res, result);
268→    return true;
269→  }
270→
271→  // 4-segment with param: /api/prompt-templates/{id}/checkout
272→  if (checkoutRoute.match(req.method, pathSegments)) {
273→    const parsed = await checkoutRoute.parse(req, res, pathSegments, queryParams);
274→    if (!parsed) return true;
275→
276→    try {
277→      const template = checkoutPromptTemplate(parsed.params.id, parsed.body.version);
278→      json(res, { template });
279→    } catch (error) {
280→      const message = error instanceof Error ? error.message : "Unknown error";
281→      if (message.includes("not found")) {
282→        jsonError(res, message, 404);
283→      } else {
284→        jsonError(res, message, 400);
285→      }
286→    }
287→    return true;
288→  }
289→
290→  // 4-segment with param: /api/prompt-templates/{id}/reset
291→  if (resetRoute.match(req.method, pathSegments)) {
292→    const parsed = await resetRoute.parse(req, res, pathSegments, queryParams);
293→    if (!parsed) return true;
294→
295→    const existing = getPromptTemplateById(parsed.params.id);
296→    if (!existing) {
297→      jsonError(res, `Prompt template ${parsed.params.id} not found`, 404);
298→      return true;
299→    }
300→
301→    const definition = getTemplateDefinition(existing.eventType);
302→    if (!definition) {
303→      jsonError(res, `No code default found for event type "${existing.eventType}"`, 404);
304→      return true;
305→    }
306→
307→    try {
308→      const template = resetPromptTemplateToDefault(parsed.params.id, definition.defaultBody);
309→      json(res, { template });
310→    } catch (error) {
311→      const message = error instanceof Error ? error.message : "Unknown error";
312→      jsonError(res, message, 400);
313→    }
314→    return true;
315→  }
316→
317→  // 3-segment with param: GET /api/prompt-templates/{id}
318→  if (getByIdRoute.match(req.method, pathSegments)) {
319→    const parsed = await getByIdRoute.parse(req, res, pathSegments, queryParams);
320→    if (!parsed) return true;
321→
322→    const template = getPromptTemplateById(parsed.params.id);
323→    if (!template) {
324→      jsonError(res, "Prompt template not found", 404);
325→      return true;
326→    }
327→
328→    const history = getPromptTemplateHistory(parsed.params.id);
329→    json(res, { template, history });
330→    return true;
331→  }
332→
333→  // 3-segment with param: DELETE /api/prompt-templates/{id}
334→  if (deleteByIdRoute.match(req.method, pathSegments)) {
335→    const parsed = await deleteByIdRoute.parse(req, res, pathSegments, queryParams);
336→    if (!parsed) return true;
337→
338→    try {
339→      const deleted = deletePromptTemplate(parsed.params.id);
340→      if (!deleted) {
341→        jsonError(res, "Prompt template not found", 404);
342→        return true;
343→      }
344→      json(res, { deleted: true });
345→    } catch (error) {
346→      const message = error instanceof Error ? error.message : "Unknown error";
347→      jsonError(res, message, 400);
348→    }
349→    return true;
350→  }
351→
352→  // 2-segment: GET /api/prompt-templates
353→  if (listRoute.match(req.method, pathSegments)) {
354→    const parsed = await listRoute.parse(req, res, pathSegments, queryParams);
355→    if (!parsed) return true;
356→
357→    const templates = getPromptTemplates({
358→      eventType: parsed.query.eventType || undefined,
359→      scope: parsed.query.scope || undefined,
360→      scopeId: parsed.query.scopeId || undefined,
361→      isDefault: parsed.query.isDefault ? parsed.query.isDefault === "true" : undefined,
362→    });
363→
364→    json(res, { templates });
365→    return true;
366→  }
367→
368→  // 2-segment: PUT /api/prompt-templates
369→  if (upsertRoute.match(req.method, pathSegments)) {
370→    const parsed = await upsertRoute.parse(req, res, pathSegments, queryParams);
371→    if (!parsed) return true;
372→
373→    const {
374→      eventType,
375→      scope: rawScope,
376→      scopeId,
377→      state,
378→      body,
379→      changedBy,
380→      changeReason,
381→    } = parsed.body;
382→    const scope = rawScope ?? "global";
383→
384→    if (scope === "global" && scopeId) {
385→      jsonError(res, "Global scope must not have scopeId", 400);
386→      return true;
387→    }
388→    if ((scope === "agent" || scope === "repo") && !scopeId) {
389→      jsonError(res, "Agent/repo scope requires scopeId", 400);
390→      return true;
391→    }
392→
393→    try {
394→      const template = upsertPromptTemplate({
395→        eventType,
396→        scope,
397→        scopeId: scopeId || null,
398→        state,
399→        body,
400→        changedBy,
401→        changeReason,
402→      });
403→      json(res, { template });
404→    } catch (error) {
405→      const message = error instanceof Error ? error.message : "Unknown error";
406→      jsonError(res, message, 500);
407→    }
408→    return true;
409→  }
410→
411→  return false;
412→}
